-//! Rebuild einsum equation from input and output subscripts
-std::string rebuildEinsumEquation(
-    std::vector<std::string> const& inputSubscriptsVec, std::string const& outputSubscripts)
-{
-    std::string equation{};
-    for (auto& s : inputSubscriptsVec)
