+Status ModelRefitter::refitOnnxNode(::ONNX_NAMESPACE::NodeProto const& node, ::ONNX_NAMESPACE::GraphProto const& graph)
+{
+    // For nodes that contain subgraphs (Ifs, Loops, Scans),
