+    {
+        status = refitOnnxBatchNormNode(node, graph);
+    }
+    else if (node.op_type() == "If")
+    {
+        status = refitOnnxIfNode(node);
+    }
+    else if (node.op_type() == "Loop")
+    {
+        status = refitOnnxLoopNode(node);
+    }
+    else if (node.op_type() == "Scan")
+    {
+        status = refitOnnxScanNode(node);
+    }
