+    broadcastTensors(ctx, axisLength, indices);
+    // Create a shifted tensor that is indices + axisLength
+    auto shifted = ctx->network()->addElementWise(*indices, *axisLength, nvinfer1::ElementWiseOperation::kSUM)->getOutput(0);
