+struct InferDeleter {
+  template <typename T> void operator()(T *obj) const {
+    if (obj) {
+      obj->destroy();
+    }
+  }
+};
+template <typename T> inline std::shared_ptr<T> infer_object(T *obj) {
+  if (!obj) {
+    throw std::runtime_error("Failed to create object");
+  }
+  return std::shared_ptr<T>(obj, InferDeleter());
+}
